script.js:
// Element selection
const form = document.getElementById("myForm"),
  passwordInput = document.getElementById("password"),
  passToggleBtn = document.getElementById("pass-toggle-btn"),
  thankYouMessage = document.getElementById("thank-you-content");

// Error handling function
const showError = (field, errorText) => {
  field.classList.add("error");
  const errorElement = document.createElement("small");
  errorElement.classList.add("error-text");
  errorElement.innerText = errorText;
  field.closest(".form-group").appendChild(errorElement);
};

// Password strength check
const checkPasswordStrength = (password) =>
  /^(?=.*\d)(?=.*[a-z])(?=.*[A-Z])(?=.*[!@#$%^&*]).{8,}$/.test(password);

// Validate password
const validatePassword = (password) => {
  if (password === "") {
    showError(passwordInput, "Enter your password");
  } else if (!checkPasswordStrength(password)) {
    showError(
      passwordInput,
      "Please enter at least 8 characters with a number, symbol, lowercase, and uppercase letter."
    );
  }
};

// Form data handling
const handleFormData = (e) => {
  e.preventDefault();
  const [fullnameInput, emailInput, dateInput, genderInput] = [
    "fullname",
    "email",
    "date",
    "gender"
  ].map((id) => document.getElementById(id));

  const [fullname, email, password, date, gender] = [
    fullnameInput,
    emailInput,
    passwordInput,
    dateInput,
    genderInput
  ].map((input) => input.value.trim());

  const emailPattern = /^[^ ]+@[^ ]+\.[a-z]{2,3}$/;

  document
    .querySelectorAll(".form-group .error")
    .forEach((field) => field.classList.remove("error"));
  document
    .querySelectorAll(".error-text")
    .forEach((errorText) => errorText.remove());

  if (fullname === "") showError(fullnameInput, "Enter your full name");
  if (!emailPattern.test(email))
    showError(emailInput, "Enter a valid email address");
  validatePassword(password);
  if (date === "") showError(dateInput, "Select your date of birth");
  if (gender === "") showError(genderInput, "Select your gender");

  if (!document.querySelectorAll(".form-group .error").length) {
    form.style.display = "none";
    thankYouMessage.style.display = "block";
  }
};

// Toggle password visibility
passToggleBtn.addEventListener("click", () => {
  passToggleBtn.className =
    passwordInput.type === "password"
      ? "fa-solid fa-eye-slash"
      : "fa-solid fa-eye";
  passwordInput.type = passwordInput.type === "password" ? "text" : "password";
});

// Form submission event handling
form.addEventListener("submit", handleFormData);

style.css:
@import url("https://fonts.googleapis.com/css2?family=Open+Sans:wght@400;500;600;700&display=swap");

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Open Sans", sans-serif;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 10px;
  min-height: 100vh;
  background: #2c3e50;
}

form {
  padding: 25px;
  background: #ecf0f1;
  max-width: 500px;
  width: 100%;
  border-radius: 7px;
  box-shadow: 0 10px 15px rgba(0, 0, 0, 0.05);
  color: #2c3e50;
}

form h2 {
  font-size: 27px;
  text-align: center;
  margin: 0px 0 30px;
}

form .form-group {
  margin-bottom: 15px;
  position: relative;
}

form label {
  display: block;
  font-size: 15px;
  margin-bottom: 7px;
}

form input,
form select {
  height: 45px;
  padding: 10px;
  width: 100%;
  font-size: 15px;
  outline: none;
  background: #fff;
  border-radius: 3px;
  border: 1px solid #bfbfbf;
}

form input:focus,
form select:focus {
  border-color: #9a9a9a;
}

form input.error,
form select.error {
  border-color: #f91919;
  background: #f9f0f1;
}

form small {
  font-size: 14px;
  margin-top: 5px;
  display: block;
  color: #f91919;
}

form .password i {
  position: absolute;
  right: 0px;
  height: 45px;
  top: 28px;
  font-size: 13px;
  line-height: 45px;
  width: 45px;
  cursor: pointer;
  color: #939393;
  text-align: center;
}

.submit-btn {
  margin-top: 30px;
  text-align: center;
}

.submit-btn input {
  color: #ffffff;
  border: none;
  height: 50px;
  width: 100%;
  font-size: 18px;
  padding: 0;
  border-radius: 8px;
  cursor: pointer;
  font-weight: 600;
  text-transform: uppercase;
  background: #000000;
  transition: background 0.3s ease, transform 0.3s ease;
  overflow: hidden;
}

.submit-btn input:hover {
  background: #1a1a1a;
}

.submit-btn input:active {
  transform: scale(0.95);
}
